        "AU3014": {
                "name": "1.2 COMPUTATIONAL AERODYNAMICS",
                "regulation": "R2021",
                "department": "AU_R2021",
                "credits": 3,
                "ltp": "3-0-0",
                "objectives": [
                        "The objective of this course is to provide the students with knowledge in the aspects of numerical discretization techniques such as finite volume and finite difference methods to show their impact on computational aerodynamics."
                ],
                "outcomes": [
                        {
                                "id": "CO1",
                                "desc": "Summarize the concepts of computational fluid dynamics and its applications in industries as a tool for fluid analysis."
                        },
                        {
                                "id": "CO2",
                                "desc": "Choose the type of flow from the finite control volume and infinitesimal small fluid element for the fluid flow analysis."
                        },
                        {
                                "id": "CO3",
                                "desc": "Select the quasi linear partial differential equation for estimating the behavior in computational fluid dynamics."
                        },
                        {
                                "id": "CO4",
                                "desc": "Identify CFD techniques for relevant partial differential equations for getting analytical solutions for fluid flow problems."
                        },
                        {
                                "id": "CO5",
                                "desc": "Apply the grid generation and transformation techniques in implementation of finite difference and finite volume methods in solving complex fluid and aerodynamic problems."
                        }
                ],
                "units": [
                        {
                                "id": 1,
                                "title": "INTRODUCTION TO COMPUTATIONAL AERODYNAMICS",
                                "topics": [
                                        "Need of computational fluid dynamics, philosophy of CFD, CFD as a research tool as a design tool, applications in various branches of engineering, models of fluid flow finite control volume, infinitesimal fluid element, substantial derivative physical meaning of divergence of velocity, derivation of continuity, momentum and energy equations, physical boundary conditions significance of conservation and non-conservation forms and their implication on CFD applications strong and weak conservation forms shock capturing and shock fitting approaches",
                                        "UNIT II MATHEMATICAL BEHAVIOR OF PARTIAL DIFFERENTIAL EQUATIONS AND THEIR IMPACT ON COMPUTATIONAL AERODYNAMICS Classification of quasi-linear partial differential equations by Cramer’s rule and Eigen value method, general behaviour of different classes of partial differential equations and their importance in understanding physical and CFD aspects of aerodynamic problems at different Mach numbers involving hyperbolic, parabolic and elliptic equations: domain of dependence and range of influence for hyperbolic equations, well-posed problems"
                                ]
                        },
                        {
                                "id": 2,
                                "title": "MATHEMATICAL BEHAVIOR OF PARTIAL DIFFERENTIAL EQUATIONS AND THEIR IMPACT ON COMPUTATIONAL AERODYNAMICS",
                                "topics": [
                                        "THEIR IMPACT ON COMPUTATIONAL AERODYNAMICS Classification of quasi-linear partial differential equations by Cramer’s rule and Eigen value method, general behaviour of different classes of partial differential equations and their importance in understanding physical and CFD aspects of aerodynamic problems at different Mach numbers involving hyperbolic, parabolic and elliptic equations: domain of dependence and range of influence for hyperbolic equations, well-posed problems",
                                        "UNIT III BASIC ASPECTS OF DISCRETIZATION Introduction to finite difference: finite difference approximation for first order, second order and mixed derivatives, explicit and implicit approaches, truncation and round-off errors, consistency, stability, accuracy, convergence, efficiency of numerical solutions",
                                        "Von Neumann stability analysis, physical significance of CFL stability condition",
                                        "Need for grid generation, structured grids artesian grids, stretched (compressed) grids, body fitted structured grids, H-mesh, C-mesh, O-mesh, Imesh, multi-block grids, C-H mesh, H-O-H mesh, overset grids, adaptive grids, unstructured grids: triangular, tetrahedral cells, hybrid grids, quadrilateral, hexahedral cells"
                                ]
                        },
                        {
                                "id": 3,
                                "title": "BASIC ASPECTS OF DISCRETIZATION",
                                "topics": [
                                        "Introduction to finite difference: finite difference approximation for first order, second order and mixed derivatives, explicit and implicit approaches, truncation and round-off errors, consistency, stability, accuracy, convergence, efficiency of numerical solutions",
                                        "Von Neumann stability analysis, physical significance of CFL stability condition",
                                        "Need for grid generation, structured grids artesian grids, stretched (compressed) grids, body fitted structured grids, H-mesh, C-mesh, O-mesh, Imesh, multi-block grids, C-H mesh, H-O-H mesh, overset grids, adaptive grids, unstructured grids: triangular, tetrahedral cells, hybrid grids, quadrilateral, hexahedral cells",
                                        "UNIT IV CFD TECHNIQUES Lax-Wendroff technique, MacCormack’s technique, Crank Nicholson technique, Relaxation technique, aspects of numerical dissipation and dispersion",
                                        "Alternating-Direction-Implicit (ADI) Technique, pressure correction technique: application to incompressible viscous flow, need for staggered grid",
                                        "Philosophy of pressure correction method, pressure correction formula",
                                        "Numerical procedures: SIMPLE, SIMPLER, SIMPLEC and PISO algorithms, boundary conditions for the pressure correction method"
                                ]
                        },
                        {
                                "id": 4,
                                "title": "CFD TECHNIQUES",
                                "topics": [
                                        "Lax-Wendroff technique, MacCormack’s technique, Crank Nicholson technique, Relaxation technique, aspects of numerical dissipation and dispersion",
                                        "Alternating-Direction-Implicit (ADI) Technique, pressure correction technique: application to incompressible viscous flow, need for staggered grid",
                                        "Philosophy of pressure correction method, pressure correction formula",
                                        "Numerical procedures: SIMPLE, SIMPLER, SIMPLEC and PISO algorithms, boundary conditions for the pressure correction method",
                                        "UNIT V FINITE VOLUME METHODS Basis of finite volume method, conditions on the finite volume selections, cell-centered and cell vertex approaches",
                                        "Definition of finite volume discretization, general formulation of a numerical scheme, two dimensional finite volume method with example"
                                ]
                        },
                        {
                                "id": 5,
                                "title": "FINITE VOLUME METHODS",
                                "topics": [
                                        "Basis of finite volume method, conditions on the finite volume selections, cell-centered and cell vertex approaches",
                                        "Definition of finite volume discretization, general formulation of a numerical scheme, two dimensional finite volume method with example",
                                        "TOTAL:  PERIODS"
                                ]
                        }
                ]
        },
